+function applyAccountName(params: {
+  cfg: ClawdbotConfig;
+  provider: ChatProvider;
+  accountId: string;
+  name?: string;
+}): ClawdbotConfig {
+  const trimmed = params.name?.trim();
+  if (!trimmed) return params.cfg;
+  const accountId = normalizeAccountId(params.accountId);
+  if (params.provider === "whatsapp") {
+    return {
+      ...params.cfg,
+      whatsapp: {
+        ...params.cfg.whatsapp,
+        accounts: {
+          ...params.cfg.whatsapp?.accounts,
+          [accountId]: {
+            ...params.cfg.whatsapp?.accounts?.[accountId],
+            name: trimmed,
+          },
+        },
+      },
+    };
+  }
+  const key = params.provider;
+  if (accountId === DEFAULT_ACCOUNT_ID) {
+    const baseConfig = (params.cfg as Record<string, unknown>)[key];
+    const safeBase =
+      typeof baseConfig === "object" && baseConfig
+        ? (baseConfig as Record<string, unknown>)
+        : {};
+    return {
+      ...params.cfg,
+      [key]: {
+        ...safeBase,
+        name: trimmed,
+      },
+    } as ClawdbotConfig;
+  }
+  const base = (params.cfg as Record<string, unknown>)[key] as
+    | { accounts?: Record<string, Record<string, unknown>> }
+    | undefined;
+  const baseAccounts: Record<
+    string,
+    Record<string, unknown>
+  > = base?.accounts ?? {};
+  const existingAccount = baseAccounts[accountId] ?? {};
+  return {
+    ...params.cfg,
+    [key]: {
+      ...base,
+      accounts: {
+        ...baseAccounts,
+        [accountId]: {
+          ...existingAccount,
+          name: trimmed,
+        },
+      },
+    },
+  } as ClawdbotConfig;
